from sympy import factorint
def sopf(n): return sum(factorint(n))
def ok(n): return n != (r:=int(str(n)[::-1])) and sopf(n) == sopf(r)
print([k for k in range(20000) if ok(k)]) # _Michael S. Branicky_, Mar 05 2026

